-- =============================================================================
-- jeju-island-private-car-charter-tour — detail_payload surgical update (6 locales)
-- =============================================================================
-- Generated: 2026-06-23  (branch: claude/private-tour-sample-itinerary-7kwkjp)
--
-- WHAT THIS DOES (matches the static JSON bundle change):
--   * itineraryStops              → 3 SAMPLE route slots (East / South / Southwest)
--                                    — slot skeletons only; detailed stops to be
--                                      imported from the bus tours later.
--   * whyTourWorks.routeLogicSections → [] (route-selection "logic" removed)
--   * practicalAccordionItems     → refreshed incl. the "included" item
--                                    (variant normalized to "included",
--                                     only admission + meals excluded)
--   * hero.pills[2]               → "East · South · Southwest" routes
--   * privateTourPolicy           → NEW "how the private tour works" rules block,
--                                    rendered directly below the itinerary.
--
-- Pickup/drop-off is already hotel-default (pickup_dropoff.type = hotel_pickup);
-- left untouched.
--
-- SAFETY: surgical jsonb_set on changed keys ONLY. hero.imageUrl, gallery images,
-- card/seo/price columns and any other DB-only fields are PRESERVED.
--
-- This is an UPDATE (not an upsert): it only touches rows that already exist for
-- this slug. If the row is absent in the target DB, that locale is a no-op — run
-- the product's full insert first, then re-run this.
--
-- Idempotent: re-running produces the same payload.
-- =============================================================================

BEGIN;

-- locale=ko
UPDATE public.tour_product_pages SET
  detail_payload =
    jsonb_set(
    jsonb_set(
    jsonb_set(
    jsonb_set(
    jsonb_set(
      detail_payload,
      '{itineraryStops}',                  $jpc$[{"number":1,"name":"동부 코스 — 유네스코 & K-드라마 해안 (샘플)","category":"성산일출봉 · 만장굴 · 섭지코지 · 우도","description":"제주 동부 버스투어 일정을 기반으로 한 샘플 코스입니다. 프라이빗 차터에서는 이 코스를 그대로 따르거나 원하는 장소로 자유롭게 조정할 수 있으며, 드라이버 가이드가 날씨와 교통 상황에 맞춰 방문 순서를 조율합니다. 상세 일정은 추후 업데이트 예정이며, 입장료와 식사는 포함되지 않습니다(각 장소에서 직접 결제).","highlights":["성산일출봉 — 유네스코 세계자연유산, 분화구 정상 전망 (입장료 별도)","만장굴 — 세계 최대급 용암동굴 (재개방 여부 사전 확인)","섭지코지 — K-드라마 '올인' 촬영지 해안 곶","우도 — 페리로 닿는 부속 섬 (선택, 페리 요금 별도)"],"timeUsed":["호텔 픽업 후 동부 해안으로 이동","오전 대표 명소 2~3곳 (드라이버 가이드가 순서 조율)","점심 식사 — 자유 선택 (미포함)","오후 명소 관람 후 호텔 드롭오프"],"_poi_meta":{"poi_key":"route_variant_east","match":"route_variant_no_single_poi","constituent_pois":["seongsan_ilchulbong","manjanggul_lava_tube","seopjikoji","udo_island"],"source_bus_tour":"jeju-eastern-unesco-spots-day-tour","pending_import":true,"note":"Sample route slot for the private charter — mirrors the jeju-eastern-unesco-spots-day-tour bus tour. Detailed stop-by-stop content to be imported later."}},{"number":2,"name":"남부 코스 — 폭포 & 화산 해안 (샘플)","category":"천지연폭포 · 주상절리 · 산방산 · 올레시장","description":"제주 남부 버스투어 일정을 기반으로 한 샘플 코스입니다. 프라이빗 차터에서는 이 코스를 그대로 따르거나 원하는 장소로 자유롭게 조정할 수 있으며, 드라이버 가이드가 날씨와 교통 상황에 맞춰 방문 순서를 조율합니다. 상세 일정은 추후 업데이트 예정이며, 입장료와 식사는 포함되지 않습니다(각 장소에서 직접 결제).","highlights":["천지연폭포 — 낙차 22m 폭포, 아열대 숲길 산책","대포 주상절리대 — 해안 육각 현무암 기둥, 유네스코 세계지질공원","산방산 — 조면암 용암 돔과 동굴 사원 산방굴사","서귀포 올레시장 — 한라봉·흑돼지·문어빵 길거리 먹거리"],"timeUsed":["호텔 픽업 후 남부 해안으로 이동","오전 대표 명소 2~3곳 (드라이버 가이드가 순서 조율)","점심 식사 — 자유 선택 (미포함)","오후 명소 관람 후 호텔 드롭오프"],"_poi_meta":{"poi_key":"route_variant_south","match":"route_variant_no_single_poi","constituent_pois":["cheonjiyeon_falls","jusangjeolli_cliffs","sanbangsan","seogwipo_olle_market"],"source_bus_tour":"jeju-southern-top-unesco-spots-tour","pending_import":true,"note":"Sample route slot for the private charter — mirrors the jeju-southern-top-unesco-spots-tour bus tour. Detailed stop-by-stop content to be imported later."}},{"number":3,"name":"서남부 코스 — 해변 & 차밭 (샘플)","category":"협재해변 · 한림공원 · 오설록 · 산방산","description":"제주 서남부 버스투어 일정을 기반으로 한 샘플 코스입니다. 프라이빗 차터에서는 이 코스를 그대로 따르거나 원하는 장소로 자유롭게 조정할 수 있으며, 드라이버 가이드가 날씨와 교통 상황에 맞춰 방문 순서를 조율합니다. 상세 일정은 추후 업데이트 예정이며, 입장료와 식사는 포함되지 않습니다(각 장소에서 직접 결제).","highlights":["협재해변 — 에메랄드빛 바다와 비양도 전망","한림공원 — 아열대 정원과 협재·쌍용 동굴","오설록 티뮤지엄 — 차밭과 녹차 디저트 (입장 무료)","산방산·송악산 — 화산 해안 절경과 산책로"],"timeUsed":["호텔 픽업 후 서남부 해안으로 이동","오전 대표 명소 2~3곳 (드라이버 가이드가 순서 조율)","점심 식사 — 자유 선택 (미포함)","오후 명소 관람 후 호텔 드롭오프"],"_poi_meta":{"poi_key":"route_variant_southwest","match":"route_variant_no_single_poi","constituent_pois":["hyeopjae_beach","hallim_park","osulloc_tea_museum","sanbangsan"],"source_bus_tour":"jeju-west-south-full-day-authentic-tour","pending_import":true,"note":"Sample route slot for the private charter — mirrors the jeju-west-south-full-day-authentic-tour bus tour. Detailed stop-by-stop content to be imported later."}}]$jpc$::jsonb, true),
      '{whyTourWorks,routeLogicSections}', $jpc$[]$jpc$::jsonb, true),
      '{practicalAccordionItems}',         $jpc$[{"id":"pickup","title":"픽업 및 드롭오프","preview":"제주 전 지역 호텔 픽업 가능, 출발 10분 전 로비 대기 부탁드립니다","content":["제주도 전 지역 호텔 픽업이 포함되어 있습니다(제주시, 서귀포, 중문 등)","픽업은 보통 오전 8시에서 9시 사이에 이루어집니다","협의된 출발 시간 10분 전에 호텔 로비에서 대기해 주시기 바랍니다","제주 내 호텔 또는 원하시는 장소(예: 저녁 식당, 공항 등)에서 하차 가능합니다","귀환은 보통 9시간 이내 기준으로 오후 5시에서 6시 사이입니다","일정 변경이 필요할 경우, 예약일 기준 최소 2일 전까지 운영사에 연락해 주시기 바랍니다"]},{"id":"vehicle","title":"차량 및 인원 안내","preview":"인원 수 및 수하물 양에 따라 차량이 배정됩니다","content":["탑승 인원과 짐의 수량에 맞춰 적합한 차량이 배정됩니다","예약 시 정확한 탑승 인원 수와 수하물 수를 입력해 주시기 바랍니다","일반적인 차량은 1~3명에게는 세단, 4~5명에게는 중형 SUV, 6~9명에게는 스타리아 또는 카니발 밴이 제공됩니다","대규모 그룹은 여러 차량으로 나뉘거나 별도 견적이 제공될 수 있습니다"]},{"id":"duration","title":"9시간 이용 및 초과 요금","preview":"픽업 시점부터 엄격히 9시간 서비스가 제공됩니다","content":["9시간은 호텔 픽업 시간부터 시작됩니다","초과 시간은 추가 1시간당 25,000원이며, 기사에게 현금으로 직접 지불합니다","초과 운행은 기사의 가능 여부 및 해당 운행 규정에 따라 달라질 수 있습니다","우도 도선(페리) 이용 시간은 별도 합의가 없는 한 9시간 이내에 포함됩니다"]},{"id":"extras","title":"알아두어야 할 추가 비용","preview":"우도 페리, 입장료 및 식사 비용","content":["우도 차량 페리: 차량 크기에 따라 추가 비용 발생(별도 문의); 도보 승객 페리는 1인당 왕복 약 10,500원부터","모든 입장료는 각 장소에서 직접 지불합니다","식사 비용은 직접 지불하며, 드라이버 가이드가 현지 특산 음식(흑돼지, 고기국수, 전복죽 등)을 추천해 드립니다","드라이버 팁은 감사히 받지만 필수는 아닙니다"]},{"id":"weather","title":"날씨 정책","preview":"프라이빗 투어 형식은 제주의 변화하는 날씨 상황에 유연하게 대응합니다","content":["가벼운 비: 대부분의 일정은 정상 운영되며, 드라이버 가이드가 실내 코스 위주로 조정할 수 있습니다","강풍: 성산일출봉, 주상절리, 애월 등 해안가 노출 구간이 단축될 수 있습니다","태풍 경보 발령 시: 운영사에서 연락하여 일정을 재조정해 드립니다","한라산에 눈이 쌓이면 1100고지 도로가 통제될 수 있으며, 드라이버 가이드가 대체 내륙 코스로 변경합니다"]},{"id":"included","title":"포함 사항","preview":"차량과 공인 드라이버 가이드, 호텔 픽업·드롭오프까지 포함 — 입장료와 식사만 별도입니다.","variant":"included","content":["그룹 규모에 맞는 프라이빗 차량 (세단·SUV·밴)","영어 가능 공인 드라이버 가이드","제주 전 지역 호텔 픽업 및 드롭오프","기본 코스의 주유비·통행료·주차료","입장료 — 각 명소에서 직접 결제","식사 — 자유롭게 선택 (직접 결제)"],"includedCount":4}]$jpc$::jsonb, true),
      '{hero,pills}',                      $jpc$["프라이빗 차량","공인 드라이버 가이드","동부 · 남부 · 서남부 코스"]$jpc$::jsonb, true),
      '{privateTourPolicy}',               $jpc${"title":"프라이빗 투어 이용 안내","subtitle":"예약 전 꼭 확인해 주세요","groups":[{"icon":"route","title":"일정과 코스","items":["위 동부·남부·서남부 샘플 코스 중에서 선택하거나, 가고 싶은 장소로 하루를 자유롭게 구성할 수 있습니다.","드라이버 가이드가 날씨·교통·페리 시간에 맞춰 방문 순서와 동선을 조율합니다.","코스나 일정 변경은 예약일 기준 최소 2일 전에 요청해 주세요."]},{"icon":"pickup","title":"픽업 · 드롭오프 (호텔 기본)","items":["제주 전 지역(제주시·서귀포·중문) 호텔에서 도어 투 도어 픽업·드롭오프가 기본입니다.","출발 예정 시각 10분 전까지 호텔 로비에서 대기해 주세요.","제주공항 픽업·샌딩도 가능하며, 9시간 운행 시간에 포함됩니다."]},{"icon":"time","title":"이용 시간 · 초과 요금","items":["기본 9시간이며, 픽업 시각부터 시작됩니다.","초과 시 시간당 25,000원이 추가되며 드라이버에게 현금으로 지불합니다(드라이버 일정에 따라 연장 가능 여부가 달라질 수 있습니다)."]},{"icon":"price","title":"요금 · 미포함 항목","items":["요금은 인원이 아닌 차량 단위로 책정됩니다.","입장료와 식사는 포함되지 않으며, 각 명소와 식당에서 직접 결제합니다.","개인 쇼핑과 기사 팁은 별도입니다."]}]}$jpc$::jsonb, true),
  updated_at = NOW()
WHERE slug = 'jeju-island-private-car-charter-tour' AND locale = 'ko';

-- locale=en
UPDATE public.tour_product_pages SET
  detail_payload =
    jsonb_set(
    jsonb_set(
    jsonb_set(
    jsonb_set(
    jsonb_set(
      detail_payload,
      '{itineraryStops}',                  $jpc$[{"number":1,"name":"East Route — UNESCO & K-Drama Coast (Sample)","category":"Seongsan · Manjanggul · Seopjikoji · Udo","description":"A sample route based on our Jeju eastern bus-tour itinerary. On a private charter you can follow it as-is or freely adjust the stops, and your driver-guide reorders the day around weather and traffic. The detailed stop-by-stop plan will be added soon; admission fees and meals are not included (paid directly at each venue).","highlights":["Seongsan Ilchulbong — UNESCO World Heritage tuff cone with crater-rim views (admission extra)","Manjanggul — one of the world's largest lava tubes (confirm reopening before travel)","Seopjikoji — coastal cape made famous by the K-drama 'All In'","Udo — island reached by ferry (optional; ferry fare extra)"],"timeUsed":["Hotel pickup, then drive to the eastern coast","Two to three morning highlights (your driver-guide sets the order)","Lunch — free choice (not included)","Afternoon sights, then hotel drop-off"],"_poi_meta":{"poi_key":"route_variant_east","match":"route_variant_no_single_poi","constituent_pois":["seongsan_ilchulbong","manjanggul_lava_tube","seopjikoji","udo_island"],"source_bus_tour":"jeju-eastern-unesco-spots-day-tour","pending_import":true,"note":"Sample route slot for the private charter — mirrors the jeju-eastern-unesco-spots-day-tour bus tour. Detailed stop-by-stop content to be imported later."}},{"number":2,"name":"South Route — Waterfalls & Volcanic Coast (Sample)","category":"Cheonjiyeon · Jusangjeolli · Sanbangsan · Olle Market","description":"A sample route based on our Jeju southern bus-tour itinerary. On a private charter you can follow it as-is or freely adjust the stops, and your driver-guide reorders the day around weather and traffic. The detailed stop-by-stop plan will be added soon; admission fees and meals are not included (paid directly at each venue).","highlights":["Cheonjiyeon Falls — 22 m waterfall reached via a subtropical forest walk","Jusangjeolli Cliffs — hexagonal basalt columns, UNESCO Global Geopark","Sanbangsan — trachyte lava dome with the Sanbanggulsa cave temple","Seogwipo Olle Market — Hallabong, black-pork and octopus-bread street food"],"timeUsed":["Hotel pickup, then drive to the southern coast","Two to three morning highlights (your driver-guide sets the order)","Lunch — free choice (not included)","Afternoon sights, then hotel drop-off"],"_poi_meta":{"poi_key":"route_variant_south","match":"route_variant_no_single_poi","constituent_pois":["cheonjiyeon_falls","jusangjeolli_cliffs","sanbangsan","seogwipo_olle_market"],"source_bus_tour":"jeju-southern-top-unesco-spots-tour","pending_import":true,"note":"Sample route slot for the private charter — mirrors the jeju-southern-top-unesco-spots-tour bus tour. Detailed stop-by-stop content to be imported later."}},{"number":3,"name":"West–South Route — Beaches & Tea Fields (Sample)","category":"Hyeopjae Beach · Hallim Park · O'sulloc · Sanbangsan","description":"A sample route based on our Jeju west–south bus-tour itinerary. On a private charter you can follow it as-is or freely adjust the stops, and your driver-guide reorders the day around weather and traffic. The detailed stop-by-stop plan will be added soon; admission fees and meals are not included (paid directly at each venue).","highlights":["Hyeopjae Beach — emerald water with views of Biyangdo islet","Hallim Park — subtropical gardens and the Hyeopjae/Ssangyong caves","O'sulloc Tea Museum — tea fields and green-tea desserts (free entry)","Sanbangsan & Songaksan — volcanic coastline scenery and walking trails"],"timeUsed":["Hotel pickup, then drive to the west–south coast","Two to three morning highlights (your driver-guide sets the order)","Lunch — free choice (not included)","Afternoon sights, then hotel drop-off"],"_poi_meta":{"poi_key":"route_variant_southwest","match":"route_variant_no_single_poi","constituent_pois":["hyeopjae_beach","hallim_park","osulloc_tea_museum","sanbangsan"],"source_bus_tour":"jeju-west-south-full-day-authentic-tour","pending_import":true,"note":"Sample route slot for the private charter — mirrors the jeju-west-south-full-day-authentic-tour bus tour. Detailed stop-by-stop content to be imported later."}}]$jpc$::jsonb, true),
      '{whyTourWorks,routeLogicSections}', $jpc$[]$jpc$::jsonb, true),
      '{practicalAccordionItems}',         $jpc$[{"id":"pickup","title":"Pickup & drop-off","preview":"Hotel pickup anywhere on Jeju; lobby meeting 10 minutes early","content":["Hotel pickup is included anywhere on Jeju Island (Jeju City, Seogwipo, Jungmun, etc.)","Pickup is typically arranged between 08:00 and 09:00","Please wait at the hotel lobby 10 minutes before the agreed departure time","Drop-off at your Jeju hotel or any Jeju-island location of your choice (e.g., a dinner restaurant or the airport)","Return is typically between 17:00 and 18:00 within the 9-hour service time","If you need to reschedule, please contact the local team at least 2 days before the original reservation date"]},{"id":"vehicle","title":"Vehicle and Group Size","preview":"Vehicle assigned by group size and luggage volume","content":["The vehicle type is matched to the exact number of passengers and luggage pieces","Please fill in the exact passenger count and luggage count when booking","Typical vehicles include sedans for 1 to 3 guests, mid-size SUVs for 4 to 5 guests, and Staria or Carnival vans for 6 to 9 guests","Larger groups may be split across multiple vehicles or quoted separately"]},{"id":"duration","title":"9-Hour Service and Overtime","preview":"Strict 9-hour service time from pickup","content":["The 9-hour service time starts from your hotel pickup time","Overtime is charged at 25,000 KRW per additional hour, paid in cash directly to the driver","Overtime is subject to driver availability and applicable hours of service rules","Udo Island ferry crossings count within the 9-hour service time unless otherwise agreed"]},{"id":"extras","title":"Extra Fees You Should Know About","preview":"Udo ferry, admission costs, and meals","content":["Udo Island vehicle ferry: extra cost (varies by vehicle size); foot-passenger ferry from ≈10,500 KRW round-trip per person","All admission fees are paid directly at each venue","Meals are paid directly; the driver-guide can recommend local specialties (heuk dwaeji black pork, gogi guksu, abalone porridge)","Optional driver gratuities are appreciated but not required"]},{"id":"weather","title":"Weather policy","preview":"Private format adapts well to changing Jeju conditions","content":["Light rain: most stops still operate; the driver-guide can shift toward indoor stops","Strong wind: coastal exposure at Seongsan, Jusangjeolli, and Aewol may be shortened","Typhoon-warning days: the local team will contact you to reschedule","Snow on Hallasan can close the 1100 Highland road; the driver-guide will substitute alternative inland stops"]},{"id":"included","title":"What's included","preview":"Vehicle, licensed driver-guide and hotel pickup/drop-off — only admission and meals are separate.","variant":"included","content":["Private vehicle (sedan, SUV or van based on group size)","Licensed English-speaking driver-guide","Hotel pickup and drop-off anywhere on Jeju","Fuel, tolls and parking for the standard route","Admission fees — paid directly at each venue","Meals — your choice (paid directly)"],"includedCount":4}]$jpc$::jsonb, true),
      '{hero,pills}',                      $jpc$["Private Vehicle","Licensed Driver-Guide","East · South · West–South Routes"]$jpc$::jsonb, true),
      '{privateTourPolicy}',               $jpc${"title":"Before you book — how the private tour works","subtitle":"A few things worth knowing first","groups":[{"icon":"route","title":"Itinerary & route","items":["Pick one of the East / South / West–South sample routes above, or build the day freely around the places you want to see.","Your driver-guide orders the stops and the route around weather, traffic and ferry times.","Request any route or schedule change at least 2 days before your booking date."]},{"icon":"pickup","title":"Pickup & drop-off (hotel by default)","items":["Door-to-door hotel pickup and drop-off anywhere on Jeju (Jeju City, Seogwipo, Jungmun) is the default.","Please wait in the hotel lobby 10 minutes before the scheduled pickup time.","Jeju Airport pickup or send-off is also available and counts within the 9-hour service."]},{"icon":"time","title":"Hours & overtime","items":["The standard service is 9 hours, starting from your pickup time.","Overtime is KRW 25,000 per hour, paid to the driver in cash (availability depends on the driver's schedule)."]},{"icon":"price","title":"Price & what's not included","items":["Pricing is per vehicle, not per person.","Admission fees and meals are not included — you pay them directly at each venue and restaurant.","Personal shopping and driver gratuities are separate."]}]}$jpc$::jsonb, true),
  updated_at = NOW()
WHERE slug = 'jeju-island-private-car-charter-tour' AND locale = 'en';

-- locale=ja
