      detail_payload,
      '{itineraryStops}',                  $jpc$[{"number":1,"name":"東部コース — ユネスコ＆Kドラマ海岸（サンプル）","category":"城山日出峰・万丈窟・涉地岬・牛島","description":"済州島東部バスツアーの行程をもとにしたサンプルコースです。プライベートチャーターではこのまま回ることも、お好きな場所に自由に組み替えることもでき、ドライバーガイドが天候や交通に合わせて訪問順を調整します。詳しい行程は今後追加予定で、入場料と食事は含まれません（各施設で直接お支払い）。","highlights":["城山日出峰 — ユネスコ世界自然遺産の噴火口（入場料別）","万丈窟 — 世界最大級の溶岩洞窟（再開状況を事前確認）","涉地岬 — Kドラマ「オールイン」のロケ地となった岬","牛島 — フェリーで渡る離島（任意・乗船料別）"],"timeUsed":["ホテルお迎え後、東部の海岸へ移動","午前は主要スポット2〜3か所（順番はドライバーガイドが調整）","昼食 — 自由選択（含まれません）","午後の観光後、ホテルへお送り"],"_poi_meta":{"poi_key":"route_variant_east","match":"route_variant_no_single_poi","constituent_pois":["seongsan_ilchulbong","manjanggul_lava_tube","seopjikoji","udo_island"],"source_bus_tour":"jeju-eastern-unesco-spots-day-tour","pending_import":true,"note":"Sample route slot for the private charter — mirrors the jeju-eastern-unesco-spots-day-tour bus tour. Detailed stop-by-stop content to be imported later."}},{"number":2,"name":"南部コース — 滝＆火山海岸（サンプル）","category":"天地淵滝・柱状節理・山房山・オルレ市場","description":"済州島南部バスツアーの行程をもとにしたサンプルコースです。プライベートチャーターではこのまま回ることも、お好きな場所に自由に組み替えることもでき、ドライバーガイドが天候や交通に合わせて訪問順を調整します。詳しい行程は今後追加予定で、入場料と食事は含まれません（各施設で直接お支払い）。","highlights":["天地淵滝 — 落差22mの滝、亜熱帯の森の遊歩道","大浦柱状節理帯 — 海岸の六角玄武岩柱、ユネスコ世界ジオパーク","山房山 — 粗面岩の溶岩ドームと山房窟寺","西帰浦オルレ市場 — ハルラボン・黒豚・たこ焼きパンの食べ歩き"],"timeUsed":["ホテルお迎え後、南部の海岸へ移動","午前は主要スポット2〜3か所（順番はドライバーガイドが調整）","昼食 — 自由選択（含まれません）","午後の観光後、ホテルへお送り"],"_poi_meta":{"poi_key":"route_variant_south","match":"route_variant_no_single_poi","constituent_pois":["cheonjiyeon_falls","jusangjeolli_cliffs","sanbangsan","seogwipo_olle_market"],"source_bus_tour":"jeju-southern-top-unesco-spots-tour","pending_import":true,"note":"Sample route slot for the private charter — mirrors the jeju-southern-top-unesco-spots-tour bus tour. Detailed stop-by-stop content to be imported later."}},{"number":3,"name":"西南部コース — ビーチ＆茶畑（サンプル）","category":"挾才ビーチ・翰林公園・オソルロク・山房山","description":"済州島西南部バスツアーの行程をもとにしたサンプルコースです。プライベートチャーターではこのまま回ることも、お好きな場所に自由に組み替えることもでき、ドライバーガイドが天候や交通に合わせて訪問順を調整します。詳しい行程は今後追加予定で、入場料と食事は含まれません（各施設で直接お支払い）。","highlights":["挾才ビーチ — エメラルドの海と飛揚島の眺め","翰林公園 — 亜熱帯庭園と挾才・双龍洞窟","オソルロク茶ミュージアム — 茶畑と緑茶スイーツ（入場無料）","山房山・松岳山 — 火山海岸の絶景と遊歩道"],"timeUsed":["ホテルお迎え後、西南部の海岸へ移動","午前は主要スポット2〜3か所（順番はドライバーガイドが調整）","昼食 — 自由選択（含まれません）","午後の観光後、ホテルへお送り"],"_poi_meta":{"poi_key":"route_variant_southwest","match":"route_variant_no_single_poi","constituent_pois":["hyeopjae_beach","hallim_park","osulloc_tea_museum","sanbangsan"],"source_bus_tour":"jeju-west-south-full-day-authentic-tour","pending_import":true,"note":"Sample route slot for the private charter — mirrors the jeju-west-south-full-day-authentic-tour bus tour. Detailed stop-by-stop content to be imported later."}}]$jpc$::jsonb, true),
      '{whyTourWorks,routeLogicSections}', $jpc$[]$jpc$::jsonb, true),
      '{practicalAccordionItems}',         $jpc$[{"id":"pickup","title":"送迎について","preview":"済州島内どこのホテルでもお迎え可能。出発10分前にロビーにてお集まりください","content":["済州島内のホテルであれば場所を問わずお迎えいたします（済州市・西帰浦・中文など）","お迎えは通常08:00〜09:00の間に設定されます","出発予定時刻の10分前に、ホテルのロビーにてお待ちください","済州島内のご宿泊ホテル、またはご希望の場所（夕食レストランや空港など）でお降りいただけます","ご帰着は9時間の範囲内で、通常17:00〜18:00となります","予約の変更が必要な場合は、元のご予約日の2日前までにオペレーターへご連絡ください"]},{"id":"vehicle","title":"車両とグループ人数","preview":"グループの人数と荷物量に応じて車両を手配いたします","content":["ご乗車人数と荷物の数に合わせて、最適な車両タイプをご用意します","ご予約の際は、正確な乗客数と荷物数を必ずご入力ください","一般的な車両は、1〜3名様にはセダン、4〜5名様にはミッドサイズSUV、6〜9名様にはスターリアまたはカーニバルバンをご用意しております","大人数の場合は、複数の車両に分乗いただくか、別途お見積もりとなる場合がございます"]},{"id":"duration","title":"9時間の利用時間と延長料金","preview":"お迎えから厳密に9時間のサービス時間となります","content":["9時間の利用時間は、ホテルへのお迎え時刻から開始されます","延長料金は1時間ごとに25,000ウォンで、ドライバーへ直接現金でお支払いください","延長はドライバーの空き状況および適用される乗務時間規則に従います","牛島（ウド）へのフェリー乗船時間は、別途合意がない限り9時間の利用時間に含まれます"]},{"id":"extras","title":"ご注意いただきたい追加料金について","preview":"牛島フェリー代、入場料、お食事代","content":["牛島の車両フェリー：追加費用が発生します（車両サイズにより異なります）；徒歩乗船フェリーは1名様往復約10,500ウォンから","入場料はすべて各施設にて直接お支払いください","お食事代は直接お支払いください；ドライバーガイドが地元の名物料理（黒豚〔フクテジ〕、肉そば〔コギグクス〕、アワビ粥）をご案内いたします","ドライバーへのチップは任意ですが、大変励みになります"]},{"id":"weather","title":"天候に関するポリシー","preview":"プライベートツアーは、済州島の変わりやすい天候にも柔軟に対応いたします","content":["小雨の場合：ほとんどの観光スポットは通常通りご利用いただけます；ドライバーガイドが屋内スポット中心のルートに変更することも可能です","強風の場合：城山（ソンサン）、柱状節理（チュサンジョルリ）、涯月（エウォル）の沿岸部での滞在時間が短縮される場合がございます","台風警報発令時：オペレーターよりご連絡の上、日程を変更いたします","漢拏山（ハルラサン）の積雪により1100高地道路が閉鎖される場合があります；その際はドライバーガイドが代替の内陸スポットにご案内いたします"]},{"id":"included","title":"含まれるもの","preview":"車両・公認ドライバーガイド・ホテル送迎込み — 別途は入場料と食事のみです。","variant":"included","content":["グループ人数に応じたプライベート車両（セダン・SUV・バン）","英語対応の公認ドライバーガイド","済州島全域のホテル送迎","標準コースの燃料費・通行料・駐車料","入場料 — 各施設で直接お支払い","食事 — 自由選択（直接お支払い）"],"includedCount":4}]$jpc$::jsonb, true),
      '{hero,pills}',                      $jpc$["プライベート車両","公認ドライバーガイド","東部・南部・西南部コース"]$jpc$::jsonb, true),
      '{privateTourPolicy}',               $jpc${"title":"ご予約前に — プライベートツアーのご案内","subtitle":"まずはこちらをご確認ください","groups":[{"icon":"route","title":"行程とコース","items":["上記の東部・南部・西南部サンプルコースから選ぶか、行きたい場所で1日を自由に組み立てられます。","ドライバーガイドが天候・交通・フェリーの時間に合わせて訪問順とルートを調整します。","コースや日程の変更は、予約日の2日前までにご依頼ください。"]},{"icon":"pickup","title":"送迎（ホテル基本）","items":["済州島全域（済州市・西帰浦・中文）のホテルでのドア・ツー・ドア送迎が基本です。","出発予定時刻の10分前までにホテルのロビーでお待ちください。","済州空港でのお迎え・お見送りも可能で、9時間の運行時間に含まれます。"]},{"icon":"time","title":"利用時間・超過料金","items":["標準は9時間で、お迎え時刻から開始します。","超過は1時間あたり25,000ウォンで、ドライバーへ現金でお支払いください（延長の可否はドライバーの予定により異なります）。"]},{"icon":"price","title":"料金・含まれないもの","items":["料金は人数ではなく車両単位です。","入場料と食事は含まれず、各施設・レストランで直接お支払いいただきます。","個人のお買い物やドライバーへのチップは別途です。"]}]}$jpc$::jsonb, true),
  updated_at = NOW()
WHERE slug = 'jeju-island-private-car-charter-tour' AND locale = 'ja';

