-- locale=es
UPDATE public.tour_product_pages SET
  detail_payload =
    jsonb_set(
    jsonb_set(
    jsonb_set(
    jsonb_set(
    jsonb_set(
      detail_payload,
      '{itineraryStops}',                  $jpc$[{"number":1,"name":"Ruta Este — Costa UNESCO y de K-Dramas (muestra)","category":"Seongsan · Manjanggul · Seopjikoji · Udo","description":"Una ruta de muestra basada en nuestro itinerario de bus por la zona este de Jeju. En un chárter privado puedes seguirla tal cual o ajustar las paradas libremente; tu conductor-guía reordena el día según el clima y el tráfico. El plan detallado parada por parada se añadirá pronto; las entradas y las comidas no están incluidas (se pagan directamente en cada lugar).","highlights":["Seongsan Ilchulbong — cono de toba Patrimonio de la UNESCO con vistas al cráter (entrada aparte)","Manjanggul — uno de los mayores tubos de lava del mundo (confirma su reapertura antes de viajar)","Seopjikoji — cabo costero famoso por el K-drama 'All In'","Udo — isla a la que se llega en ferry (opcional; billete aparte)"],"timeUsed":["Recogida en el hotel y traslado a la costa este","Dos o tres lugares destacados por la mañana (el conductor-guía decide el orden)","Almuerzo — a elección (no incluido)","Lugares de la tarde y regreso al hotel"],"_poi_meta":{"poi_key":"route_variant_east","match":"route_variant_no_single_poi","constituent_pois":["seongsan_ilchulbong","manjanggul_lava_tube","seopjikoji","udo_island"],"source_bus_tour":"jeju-eastern-unesco-spots-day-tour","pending_import":true,"note":"Sample route slot for the private charter — mirrors the jeju-eastern-unesco-spots-day-tour bus tour. Detailed stop-by-stop content to be imported later."}},{"number":2,"name":"Ruta Sur — Cascadas y Costa Volcánica (muestra)","category":"Cheonjiyeon · Jusangjeolli · Sanbangsan · Mercado Olle","description":"Una ruta de muestra basada en nuestro itinerario de bus por la zona sur de Jeju. En un chárter privado puedes seguirla tal cual o ajustar las paradas libremente; tu conductor-guía reordena el día según el clima y el tráfico. El plan detallado parada por parada se añadirá pronto; las entradas y las comidas no están incluidas (se pagan directamente en cada lugar).","highlights":["Cascada Cheonjiyeon — salto de 22 m al final de un paseo por bosque subtropical","Acantilados Jusangjeolli — columnas basálticas hexagonales, Geoparque Mundial UNESCO","Sanbangsan — domo de lava de traquita con el templo-cueva Sanbanggulsa","Mercado Olle de Seogwipo — comida callejera: hallabong, cerdo negro y pan de pulpo"],"timeUsed":["Recogida en el hotel y traslado a la costa sur","Dos o tres lugares destacados por la mañana (el conductor-guía decide el orden)","Almuerzo — a elección (no incluido)","Lugares de la tarde y regreso al hotel"],"_poi_meta":{"poi_key":"route_variant_south","match":"route_variant_no_single_poi","constituent_pois":["cheonjiyeon_falls","jusangjeolli_cliffs","sanbangsan","seogwipo_olle_market"],"source_bus_tour":"jeju-southern-top-unesco-spots-tour","pending_import":true,"note":"Sample route slot for the private charter — mirrors the jeju-southern-top-unesco-spots-tour bus tour. Detailed stop-by-stop content to be imported later."}},{"number":3,"name":"Ruta Suroeste — Playas y Campos de Té (muestra)","category":"Playa Hyeopjae · Parque Hallim · O'sulloc · Sanbangsan","description":"Una ruta de muestra basada en nuestro itinerario de bus por la zona suroeste de Jeju. En un chárter privado puedes seguirla tal cual o ajustar las paradas libremente; tu conductor-guía reordena el día según el clima y el tráfico. El plan detallado parada por parada se añadirá pronto; las entradas y las comidas no están incluidas (se pagan directamente en cada lugar).","highlights":["Playa Hyeopjae — agua esmeralda con vistas al islote Biyangdo","Parque Hallim — jardines subtropicales y las cuevas Hyeopjae/Ssangyong","Museo del Té O'sulloc — campos de té y postres de té verde (entrada gratuita)","Sanbangsan y Songaksan — paisajes de costa volcánica y senderos"],"timeUsed":["Recogida en el hotel y traslado a la costa suroeste","Dos o tres lugares destacados por la mañana (el conductor-guía decide el orden)","Almuerzo — a elección (no incluido)","Lugares de la tarde y regreso al hotel"],"_poi_meta":{"poi_key":"route_variant_southwest","match":"route_variant_no_single_poi","constituent_pois":["hyeopjae_beach","hallim_park","osulloc_tea_museum","sanbangsan"],"source_bus_tour":"jeju-west-south-full-day-authentic-tour","pending_import":true,"note":"Sample route slot for the private charter — mirrors the jeju-west-south-full-day-authentic-tour bus tour. Detailed stop-by-stop content to be imported later."}}]$jpc$::jsonb, true),
      '{whyTourWorks,routeLogicSections}', $jpc$[]$jpc$::jsonb, true),
      '{practicalAccordionItems}',         $jpc$[{"id":"pickup","title":"Recogida y regreso","preview":"Recogida en el hotel en cualquier punto de Jeju; reunión en el lobby 10 minutos antes","content":["La recogida en el hotel está incluida en cualquier lugar de la isla de Jeju (Ciudad de Jeju, Seogwipo, Jungmun, etc.)","La recogida se organiza habitualmente entre las 08:00 y las 09:00","Por favor, espere en el lobby del hotel 10 minutos antes de la hora de salida acordada","Regreso a su hotel en Jeju o a cualquier lugar de su elección en la isla (p. ej., un restaurante para cenar o el aeropuerto)","El regreso es generalmente entre las 17:00 y las 18:00 dentro de la ventana de 9 horas","Si necesita reprogramar, comuníquese con el operador al menos 2 días antes de la fecha de reserva original"]},{"id":"vehicle","title":"Vehículo y tamaño del grupo","preview":"Vehículo asignado según el tamaño del grupo y el volumen del equipaje","content":["El tipo de vehículo se adapta al número exacto de pasajeros y piezas de equipaje","Por favor, indique el número exacto de pasajeros y maletas al realizar la reserva","Los vehículos típicos incluyen sedanes para 1 a 3 pasajeros, SUV medianos para 4 a 5 pasajeros, y furgonetas Staria o Carnival para 6 a 9 pasajeros","Los grupos más grandes pueden distribuirse en varios vehículos o cotizarse por separado"]},{"id":"duration","title":"Ventana de 9 horas y tiempo adicional","preview":"Ventana de servicio estricta de 9 horas a partir de la recogida","content":["La ventana de 9 horas comienza desde el momento de recogida en su hotel","El tiempo adicional se cobra a 25,000 KRW por hora extra, pagado en efectivo directamente al conductor","El tiempo adicional está sujeto a la disponibilidad del conductor y a las normas de horas de servicio aplicables","Los traslados en ferry a la isla Udo cuentan dentro de la ventana de 9 horas, salvo acuerdo contrario"]},{"id":"extras","title":"Cargos adicionales que debe conocer","preview":"Ferry de Udo, costos de entrada y comidas","content":["Ferry para vehículos a isla Udo: costo adicional (varía según el tamaño del vehículo); ferry para pasajeros a pie desde aprox. 10,500 KRW ida y vuelta por persona","Todas las tarifas de entrada se pagan directamente en cada lugar","Las comidas se pagan directamente; el conductor-guía puede recomendar especialidades locales (cerdo negro heuk dwaeji, gogi guksu, gachas de abulón)","Las propinas opcionales al conductor son bienvenidas pero no obligatorias"]},{"id":"weather","title":"Política meteorológica","preview":"El formato privado se adapta bien a las cambiantes condiciones de Jeju","content":["Lluvia ligera: la mayoría de las paradas continúan operando; el conductor-guía puede redirigir hacia paradas en interiores","Viento fuerte: la exposición costera en Seongsan, Jusangjeolli y Aewol puede reducirse","Días con aviso de tifón: el operador se pondrá en contacto con usted para reprogramar","La nieve en Hallasan puede cerrar la carretera de la meseta 1100; el conductor-guía sustituirá con paradas alternativas en el interior"]},{"id":"included","title":"Qué incluye","preview":"Vehículo, conductor-guía licenciado y recogida/regreso al hotel — solo las entradas y las comidas van aparte.","variant":"included","content":["Vehículo privado (sedán, SUV o furgoneta según el grupo)","Conductor-guía licenciado de habla inglesa","Recogida y regreso al hotel en cualquier punto de Jeju","Combustible, peajes y parking de la ruta estándar","Entradas — se pagan directamente en cada lugar","Comidas — a tu elección (pago directo)"],"includedCount":4}]$jpc$::jsonb, true),
      '{hero,pills}',                      $jpc$["Vehículo Privado","Conductor-Guía Licenciado","Rutas Este / Sur / Suroeste"]$jpc$::jsonb, true),
      '{privateTourPolicy}',               $jpc${"title":"Antes de reservar — cómo funciona el tour privado","subtitle":"Conviene saber esto primero","groups":[{"icon":"route","title":"Itinerario y ruta","items":["Elige una de las rutas de muestra Este / Sur / Suroeste de arriba, o arma el día libremente con los lugares que quieras ver.","Tu conductor-guía ordena las paradas y la ruta según el clima, el tráfico y los horarios del ferry.","Solicita cualquier cambio de ruta u horario al menos 2 días antes de la fecha de reserva."]},{"icon":"pickup","title":"Recogida y regreso (hotel por defecto)","items":["La recogida y el regreso puerta a puerta en hoteles de todo Jeju (Jeju City, Seogwipo, Jungmun) son lo predeterminado.","Espera en el vestíbulo del hotel 10 minutos antes de la hora de recogida.","También es posible la recogida o el traslado en el aeropuerto de Jeju, dentro de las 9 horas de servicio."]},{"icon":"time","title":"Horario y tiempo extra","items":["El servicio estándar es de 9 horas, a contar desde la recogida.","El tiempo extra cuesta 25.000 KRW por hora, pagado al conductor en efectivo (la disponibilidad depende de su agenda)."]},{"icon":"price","title":"Precio y lo no incluido","items":["El precio es por vehículo, no por persona.","Las entradas y las comidas no están incluidas: se pagan directamente en cada lugar y restaurante.","Las compras personales y las propinas al conductor van aparte."]}]}$jpc$::jsonb, true),
  updated_at = NOW()
