COMMIT;

-- verification
SELECT slug, locale,
       jsonb_array_length(detail_payload->'itineraryStops')               AS stops,
       jsonb_array_length(detail_payload->'whyTourWorks'->'routeLogicSections') AS logic_sections,
       (detail_payload ? 'privateTourPolicy')                            AS has_policy
FROM public.tour_product_pages
WHERE slug = 'jeju-island-private-car-charter-tour'
ORDER BY locale;
